declare module 'qrcode' {
  export interface QRCodeOptions {
    width?: number;
    margin?: number;
    errorCorrectionLevel?: 'L' | 'M' | 'Q' | 'H';
    color?: { dark?: string; light?: string };
  }
  export function toDataURL(text: string, options?: QRCodeOptions): Promise<string>;
  export function toString(text: string, options?: QRCodeOptions & { type?: string }): Promise<string>;
  export function toCanvas(canvas: HTMLCanvasElement, text: string, options?: QRCodeOptions): Promise<void>;
  export function toFile(path: string, text: string, options?: QRCodeOptions): Promise<void>;
}

declare module '@capytime/tlock' {
  export interface UnlockStatus {
    canUnlock: boolean;
    unlockTime: Date | null;
    remainingSeconds: number;
    formattedRemaining?: string;
  }

  export const QUICKNET: unknown;

  export function encryptText(plaintext: string, unlockDate: Date): Promise<string>;
  export function decryptText(ciphertext: string): Promise<string>;
  export function checkUnlockStatus(ciphertext: string, network?: unknown): UnlockStatus;
}
